<template>
  <div class="inner-banner blog">
    <div class="container">
      <div class="row">
        <div class="col-sm-12">
          <div class="content">
            <h1>DOCUMENTOS EXISTENTES EN LA GACETA DE LA CARRERA.</h1>
          </div>

          <h4>
            <router-link to="/">INICIO</router-link>
          </h4>

          <h3>GACETA</h3>
        </div>
      </div>
    </div>
  </div>

  <div class="container blog-wrapper padding-lg">
    <div class="row">
      <div class="col-sm-8 blog-left">
        <div v-if="Gaceta.length == 0">
          <h2>SIN GACETA</h2>
        </div>

        <ul v-else class="row news-listing">
          <!-- <li v-for="(gac, id_gac) of Gaceta" :key="id_gac" class="col-xs-6 col-sm-6 grid-item"> -->
          <li
            v-for="(gac, id_gac) of paginatedGaceta"
            :key="id_gac"
            class="col-xs-6 col-sm-6 grid-item"
          >
            <div class="inner">
              <div class="image-container">
                <a
                  :href="url_api + '/Gaceta/' + gac.gaceta_documento"
                  target="_blank"
                >
                  <vue-pdf-embed
                    :source="url_api + '/Gaceta/' + gac.gaceta_documento"
                    :page="1"
                    :disableTextLayer="true"
                    height="400"
                  />
                </a>
              </div>

              <div class="cnt-block">
                <ul class="post-detail">
                  <li><span class="label">Gaceta</span></li>
                  <li class="comnt bg-base">
                    <span class="icon-date-icon ico"></span>
                    <span class="bold">Fecha: </span>
                    {{ dmy(gac.gaceta_fecha) }}
                  </li>
                </ul>
                <h2 style="height: 100px;">
                  <router-link
                    :to="'/detalleGaceta/' + gac.gaceta_id"
                    @click="$store.commit('clickLink')"
                  >
                    {{ gac.gaceta_titulo }}
                  </router-link>
                </h2>
                <router-link
                  :to="'/detalleGaceta/' + gac.gaceta_id"
                  @click="$store.commit('clickLink')"
                  class="read-more"
                >
                  <span class="icon-play-icon"></span>
                  Ver Documento
                </router-link>
              </div>
            </div>
          </li>
        </ul>

        <div class="text-center">
          <ul class="pagination blue">
            <li class="pagination-arrow disable">
              <a
                href="#"
                aria-label="Previous"
                @click.prevent="pag != 1 ? (pag -= 1) : ''"
              >
                <span aria-hidden="true">
                  <i class="fa fa-angle-left" aria-hidden="true"> </i>
                </span>
              </a>
            </li>

            <li v-for="(i, index) of totalPages" :key="index">
              <a
                href="#"
                :class="[i === pag ? 'active' : '']"
                @click.prevent="
                  pag = i;
                  scrollToTop();
                "
              >
                {{ i }}
              </a>
            </li>

            <li>
              <a
                href="#"
                aria-label="Next"
                @click.prevent="pag != pager ? (pag += 1) : ''"
              >
                <span aria-hidden="true">
                  <i class="fa fa-angle-right" aria-hidden="true"> </i>
                </span>
              </a>
            </li>
          </ul>
        </div>
      </div>

      <!-- Start Right Column -->
      <div class="col-sm-4">
        <SidebarCustom></SidebarCustom>
      </div>
      <!-- End Right Column -->
    </div>
  </div>
</template>

<style scoped>
.bg-overlay-img {
  background-image: url("@/assets/Fondo2.jpg");
}
</style>

<script>
import { mapState } from "vuex";
import SidebarCustom from "@/components/SidebarCustom.vue";
import VuePdfEmbed from "vue-pdf-embed";
export default {
  name: "GacetaView",
  data() {
    return {
      perPage: 4, //===

      Gaceta: [],
      search: "",
      searchGet: false,
      searchValues: [],

      NUM_RESULTS: 4,
      pag: 1,
      pager: 0,
    };
  },
  components: {
    SidebarCustom,
    VuePdfEmbed,
  },
  computed: {
    ...mapState(["url_api", "getter"]),

    totalPages() {
      //---
      return Math.ceil(this.Gaceta.length / this.perPage);
    },
    paginatedGaceta() {
      const start = (this.pag - 1) * this.perPage;
      const end = start + this.perPage;
      return this.Gaceta.slice(start, end);
    },
  },
  methods: {
    async getGacetaAll() {
      try {
        let res = await this.axios.get(
          "/api/gacetaunivAll/" + process.env.VUE_APP_ID_INSTITUCION
        );
        this.Gaceta = [];
        res.data.forEach((gaceta) => {
          if (gaceta.gaceta_estado == "1") {
            this.Gaceta.push(gaceta);
          }
        });
        this.pager = this.Gaceta.length / this.NUM_RESULTS;
        if (this.pager - Math.trunc(this.pager) > 0) {
          this.pager = Math.trunc(this.pager) + 1;
        }
        this.$store.commit("loading");
      } catch (error) {
        console.log(error);
      }
    },
    clickBack() {
      this.$store.commit("clickLink");
      this.$router.go(-1);
    },
    dmy(fecha) {
      const meses = [
        "enero",
        "febrero",
        "marzo",
        "abril",
        "mayo",
        "junio",
        "julio",
        "agosto",
        "septiembre",
        "octubre",
        "noviembre",
        "diciembre",
      ];
      let fechaCadena = fecha.substr(0, 10);
      let fechaArray = fechaCadena.split("-");
      return (
        fechaArray[2] +
        " de " +
        meses[fechaArray[1] - 1] +
        " de " +
        fechaArray[0]
      );
    },
    buscar() {
      if (this.search != "") {
        this.searchGet = true;

        this.searchValues = [];
        this.Gaceta.forEach((gac) => {
          if (
            gac.gaceta_titulo.toUpperCase().includes(this.search.toUpperCase())
          ) {
            this.searchValues.push(gac);
          }
        });
      } else {
        this.searchGet = false;
      }
    },

    scrollToTop() {
      window.scrollTo({
        top: 0,
        behavior: "smooth",
      });
    },
    
  },
  mounted() {
    this.$store.commit("loadOn");
    this.getGacetaAll();
  },
  created() {
    this.$store.commit("loadOn");
    this.getGacetaAll();
  },
};
</script>
